```typescript
export type ResearchStudyState =
  | { status: "none" }
  | { status: "open"; id: string; pi: string; enrolments: number }
  | { status: "closed"; id: string; closedAt: string };

export type ResearchStudyCommand =
  | { type: "register"; id: string; pi: string }
  | { type: "enrol" }
  | { type: "dropout" }
  | { type: "close"; at: string };

export type ResearchStudyEvent =
  | { type: "ResearchStudyRegistered"; id: string; pi: string }
  | { type: "ResearchStudyParticipantEnrolled" }
  | { type: "ResearchStudyParticipantDroppedOut" }
  | { type: "ResearchStudyClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const researchStudyDecider: Decider<ResearchStudyCommand, ResearchStudyEvent, ResearchStudyState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("STUDY_EXISTS");
        return [{ type: "ResearchStudyRegistered", id: command.id, pi: command.pi }];
      case "enrol":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "ResearchStudyParticipantEnrolled" }];
      case "dropout":
        if (state.status !== "open" || state.enrolments === 0) throw new DomainError("NO_ENROLMENT");
        return [{ type: "ResearchStudyParticipantDroppedOut" }];
      case "close":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (state.enrolments > 0) throw new DomainError("HAS_OPEN_ENROLMENTS");
        return [{ type: "ResearchStudyClosed", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ResearchStudyRegistered":
        return { status: "open", id: event.id, pi: event.pi, enrolments: 0 };
      case "ResearchStudyParticipantEnrolled":
        if (state.status !== "open") return state;
        return { ...state, enrolments: state.enrolments + 1 };
      case "ResearchStudyParticipantDroppedOut":
        if (state.status !== "open") return state;
        return { ...state, enrolments: Math.max(0, state.enrolments - 1) };
      case "ResearchStudyClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, closedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
