export type SpecimenKitState =
  | { status: "none" }
  | { status: "assembled"; id: string; items: number }
  | { status: "sealed"; id: string; items: number; sealedAt: string }
  | { status: "dispatched"; id: string; trackingRef: string };

export type SpecimenKitCommand =
  | { type: "assemble"; id: string }
  | { type: "addPart" }
  | { type: "seal"; at: string }
  | { type: "dispatch"; trackingRef: string };

export type SpecimenKitEvent =
  | { type: "SpecimenKitAssembled"; id: string }
  | { type: "SpecimenKitPartLogged" }
  | { type: "SpecimenKitSealed"; at: string }
  | { type: "SpecimenKitDispatched"; trackingRef: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const specimenKitDecider: Decider<SpecimenKitCommand, SpecimenKitEvent, SpecimenKitState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "assemble":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "SpecimenKitAssembled", id: command.id }];
      case "addPart":
        if (state.status !== "assembled") throw new DomainError("NOT_ASSEMBLED");
        return [{ type: "SpecimenKitPartLogged" }];
      case "seal":
        if (state.status !== "assembled") throw new DomainError("NOT_ASSEMBLED");
        if (state.items === 0) throw new DomainError("EMPTY");
        return [{ type: "SpecimenKitSealed", at: command.at }];
      case "dispatch":
        if (state.status !== "sealed") throw new DomainError("NOT_SEALED");
        return [{ type: "SpecimenKitDispatched", trackingRef: command.trackingRef }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SpecimenKitAssembled":
        return { status: "assembled", id: event.id, items: 0 };
      case "SpecimenKitPartLogged":
        if (state.status !== "assembled") return state;
        return { ...state, items: state.items + 1 };
      case "SpecimenKitSealed":
        if (state.status !== "assembled") return state;
        return { status: "sealed", id: state.id, items: state.items, sealedAt: event.at };
      case "SpecimenKitDispatched":
        if (state.status !== "sealed") return state;
        return { status: "dispatched", id: state.id, trackingRef: event.trackingRef };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
