      case "revoke":
        if (state.status !== "signed") throw new DomainError("NOT_SIGNED");
        return [{ type: "ConsentPackageRevoked", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ConsentPackageDrafted":
        return { status: "draft", id: event.id, subject: event.subject, clauses: 0 };
      case "ConsentClauseAdded":
        if (state.status !== "draft") return state;
        return { ...state, clauses: state.clauses + 1 };
      case "ConsentPackageSigned":
        if (state.status !== "draft") return state;
        return { status: "signed", id: state.id, subject: state.subject, signedAt: event.at };
      case "ConsentPackageRevoked":
        if (state.status !== "signed") return state;
        return { status: "revoked", id: state.id, revokedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
