```typescript
export type ResearchStudyEvent =
  | { type: "ResearchStudyRegistered"; id: string; pi: string }
  | { type: "ResearchStudyParticipantEnrolled"; pi: string }
  | { type: "ResearchStudyClosed"; pi: string };

export type PITally = { open: number; closed: number; enrolments: number };
export type ResearchStudyView = { byPI: Record<string, PITally> };

export const emptyView: ResearchStudyView = { byPI: {} };

function tally(view: ResearchStudyView, pi: string): PITally {
  return view.byPI[pi] ?? { open: 0, closed: 0, enrolments: 0 };
}

export function project(view: ResearchStudyView, event: ResearchStudyEvent): ResearchStudyView {
  switch (event.type) {
    case "ResearchStudyRegistered": {
      const next = { ...tally(view, event.pi), open: tally(view, event.pi).open + 1 };
      return { byPI: { ...view.byPI, [event.pi]: next } };
    }
    case "ResearchStudyParticipantEnrolled": {
      const next = { ...tally(view, event.pi), enrolments: tally(view, event.pi).enrolments + 1 };
      return { byPI: { ...view.byPI, [event.pi]: next } };
    }
    case "ResearchStudyClosed": {
      const cur = tally(view, event.pi);
      const next = { ...cur, open: Math.max(0, cur.open - 1), closed: cur.closed + 1 };
      return { byPI: { ...view.byPI, [event.pi]: next } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}
