```typescript
export type PublicationDraftEvent =
  | { type: "PublicationDraftStarted"; id: string; author: string }
  | { type: "PublicationDraftSubmitted"; id: string }
  | { type: "PublicationDraftAccepted"; id: string }
  | { type: "PublicationDraftRejected"; id: string; reason: string };

export type DraftRow = { id: string; author: string; status: "drafting" | "inReview" | "accepted" | "rejected"; note: string };
export type PublicationDraftView = { rows: Record<string, DraftRow> };

export const emptyView: PublicationDraftView = { rows: {} };

function update(view: PublicationDraftView, id: string, change: Partial<DraftRow>): PublicationDraftView {
  const current = view.rows[id] ?? { id, author: "", status: "drafting", note: "" };
  return { rows: { ...view.rows, [id]: { ...current, ...change } } };
}

export function project(view: PublicationDraftView, event: PublicationDraftEvent): PublicationDraftView {
  switch (event.type) {
    case "PublicationDraftStarted":
      return update(view, event.id, { id: event.id, author: event.author, status: "drafting" });
    case "PublicationDraftSubmitted":
      return update(view, event.id, { status: "inReview" });
    case "PublicationDraftAccepted":
      return update(view, event.id, { status: "accepted" });
    case "PublicationDraftRejected":
      return update(view, event.id, { status: "rejected", note: event.reason });
    default: {
      const _n: never = event;
      return view;
    }
  }
}
