export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentBiobankEntry> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1ToV2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2ToV3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentBiobankEntry };
}
