export type StoredEvent =
  | { type: "LabSampleReceived"; version: 1; sampleId: string }
  | { type: "LabSampleReceived"; version: 2; id: string; barcode: string }
  | { type: "LabSampleProcessed"; version: 1; sampleId: string };

