  | { type: "LabSampleReceived"; id: string; barcode: string }
  | { type: "LabSampleProcessed"; id: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("unknown event");
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: StoredEvent): CurrentEvent {
  switch (raw.type) {
    case "LabSampleReceived":
      if (raw.version === 1) return { type: "LabSampleReceived", id: raw.sampleId, barcode: "" };
      if (raw.version === 2) return { type: "LabSampleReceived", id: raw.id, barcode: raw.barcode };
      throw new UnknownEventError(raw);
    case "LabSampleProcessed":
      return { type: "LabSampleProcessed", id: raw.sampleId };
    default: {
      const _n: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<StoredEvent[]>;
}

export async function loadUpcasted(store: EventStore, stream: string): Promise<CurrentEvent[]> {
  const events = await store.readStream(stream);
  return events.map(upcast);
}
