// The read store is eventually consistent with the event store.
// Projections run asynchronously behind a subscription.

export type IRBApprovalCommand =
  | { type: "submit"; id: string; studyId: string }
  | { type: "approve"; expiresAt: string };

export type IRBApprovalEvent =
  | { type: "IRBApprovalSubmitted"; id: string; studyId: string }
  | { type: "IRBApprovalGranted"; expiresAt: string };

type WriteState =
  | { status: "none" }
  | { status: "pending"; id: string; studyId: string }
  | { status: "approved"; id: string; studyId: string; expiresAt: string };

const initial: WriteState = { status: "none" };

function evolve(state: WriteState, event: IRBApprovalEvent): WriteState {
  switch (event.type) {
    case "IRBApprovalSubmitted":
      return { status: "pending", id: event.id, studyId: event.studyId };
    case "IRBApprovalGranted":
      return state.status === "pending"
        ? { status: "approved", id: state.id, studyId: state.studyId, expiresAt: event.expiresAt }
        : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: IRBApprovalCommand, state: WriteState): IRBApprovalEvent[] {
  switch (command.type) {
    case "submit":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "IRBApprovalSubmitted", id: command.id, studyId: command.studyId }];
    case "approve":
      if (state.status !== "pending") throw new Error("NOT_PENDING");
      return [{ type: "IRBApprovalGranted", expiresAt: command.expiresAt }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type IRBApprovalReadView = { id: string; studyId: string; expiresAt: string | null };
export interface ReadStore { get(id: string): Promise<IRBApprovalReadView | null>; }

export async function handleCommand(
  command: IRBApprovalCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<IRBApprovalEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}

export async function queryView(id: string, store: ReadStore): Promise<IRBApprovalReadView | null> {
  return store.get(id);
}
